import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save, Globe, MapPin, GraduationCap } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminArtistForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState<any>({
    Artist_ID: '', Full_Name: '', Full_Name_In_Arabic: '',
    Nationality: '', Bio_In_English: '', Bio_In_Arabic: '',
    Gender: '', Birth_Year: '', Birth_Country: '', Current_City: ''
  });

  useEffect(() => {
    if (id) {
      AdminService.getArtistById(id).then(res => setFormData(res.data));
    }
  }, [id]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await AdminService.upsertArtist(formData);
      toast.success("Archive Entry Synchronized");
      navigate('/admin/artists');
    } catch (err) {
      toast.error("Deployment Error");
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = "w-full p-4 rounded-xl bg-gray-50 dark:bg-white/5 dark:text-white font-bold outline-none border border-transparent focus:border-primary transition-all text-xs";

  return (
    <div className="max-w-5xl mx-auto space-y-8">
      <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-[10px] font-black uppercase text-gray-400">
        <ArrowLeft size={14} /> Back to Archive
      </button>

      <div className="bg-white dark:bg-[#0a0a0a] p-12 rounded-[3.5rem] border dark:border-white/5 shadow-sm">
        <h2 className="text-4xl font-black uppercase italic mb-12">Register <span className="text-primary">Artist</span></h2>
        <form onSubmit={handleSubmit} className="space-y-12">
          
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Identity Section */}
            <div className="space-y-4">
              <h3 className="text-[10px] font-black uppercase text-primary tracking-widest">01. Identity</h3>
              <input placeholder="Artist ID (e.g. AR01)" className={inputStyle} value={formData.Artist_ID} onChange={e => setFormData({...formData, Artist_ID: e.target.value})} required />
              <input placeholder="Full Name (Eng)" className={inputStyle} value={formData.Full_Name} onChange={e => setFormData({...formData, Full_Name: e.target.value})} />
              <input placeholder="الاسم الكامل" dir="rtl" className={inputStyle} value={formData.Full_Name_In_Arabic} onChange={e => setFormData({...formData, Full_Name_In_Arabic: e.target.value})} />
            </div>

            {/* Geography Section */}
            <div className="space-y-4">
              <h3 className="text-[10px] font-black uppercase text-primary tracking-widest">02. Origin</h3>
              <input placeholder="Nationality" className={inputStyle} value={formData.Nationality} onChange={e => setFormData({...formData, Nationality: e.target.value})} />
              <input placeholder="Birth Country" className={inputStyle} value={formData.Birth_Country} onChange={e => setFormData({...formData, Birth_Country: e.target.value})} />
            </div>
          </div>

          <button disabled={loading} className="w-full py-6 bg-black dark:bg-primary text-white rounded-2xl font-black uppercase tracking-widest text-xs hover:scale-[1.02] transition-all shadow-2xl">
            {loading ? 'Processing...' : 'Commit to Archive'}
          </button>
        </form>
      </div>
    </div>
  );
};
